import { orders, products, getNextOrderId } from "../data.js";
import type { Order, OrderItem } from "../types.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

export type CreateOrderResult =
  | { success: true; order: Order }
  | { success: false; error: string; statusCode: 400 };

export type UpdateStatusResult =
  | { success: true; order: Order }
  | { success: false; error: string; statusCode: 400 | 404 };

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined && !isNaN(filters.userId)) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): EnrichedOrder | null {
  const order = orders.find((o) => o.id === id);
  if (!order) return null;

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: unknown): CreateOrderResult {
  if (
    !input ||
    typeof input !== "object" ||
    !("userId" in input) ||
    !("items" in input)
  ) {
    return {
      success: false,
      error: "userId and items are required",
      statusCode: 400,
    };
  }

  const { userId, items } = input as { userId: unknown; items: unknown };

  if (!userId || !items || !Array.isArray(items)) {
    return {
      success: false,
      error: "userId and items are required",
      statusCode: 400,
    };
  }

  if (items.length === 0) {
    return {
      success: false,
      error: "Order must have at least one item",
      statusCode: 400,
    };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of items) {
    if (!item || typeof item !== "object") {
      return {
        success: false,
        error: "userId and items are required",
        statusCode: 400,
      };
    }

    const { productId, quantity } = item as {
      productId: unknown;
      quantity: unknown;
    };

    const product = products.find((p) => p.id === productId);
    if (!product) {
      return {
        success: false,
        error: `Product ${productId} not found`,
        statusCode: 400,
      };
    }

    if (typeof quantity !== "number" || quantity <= 0) {
      return {
        success: false,
        error: "Quantity must be positive",
        statusCode: 400,
      };
    }

    if (product.stock < quantity) {
      return {
        success: false,
        error: `Insufficient stock for ${product.name}`,
        statusCode: 400,
      };
    }

    product.stock -= quantity;

    orderItems.push({
      productId: product.id,
      quantity,
      price: product.price,
    });
    total += product.price * quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: userId as number,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { success: true, order };
}

export function updateOrderStatus(
  id: number,
  status: unknown
): UpdateStatusResult {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    return { success: false, error: "Order not found", statusCode: 404 };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (typeof status !== "string" || !validStatuses.includes(status)) {
    return {
      success: false,
      error: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      statusCode: 400,
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      success: false,
      error: `Cannot transition from ${order.status} to ${status}`,
      statusCode: 400,
    };
  }

  order.status = status as Order["status"];

  return { success: true, order };
}

