import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/product-service.js";

const router = Router();

// GET /products - list all products, optionally filter by category
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const result = listProducts({
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" ? parseFloat(minPrice) : undefined,
    maxPrice: typeof maxPrice === "string" ? parseFloat(maxPrice) : undefined,
  });

  res.json(result);
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const product = getProductById(parseInt(req.params.id, 10));

  if (!product) {
    res.status(404).json({ error: "Product not found" });
    return;
  }

  res.json(product);
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  const result = adjustProductStock(
    parseInt(req.params.id, 10),
    req.body.adjustment
  );

  if (!result.success) {
    res.status(result.statusCode).json({ error: result.error });
    return;
  }

  res.json(result.product);
});

export { router as productRouter };

